"""
mkt-christ layer — Philippians chapters 1–3 (full coverage)
Output: data/commentary/mkt-christ/philippians.json
Run: python3 scripts/zc-christ-philippians-1-3-full.py

Christological spine: Christ as content of life (1:21), the Christ-hymn
(2:6-11) as the defining pattern of kenōsis → exaltation, righteousness
from faith in/of Christ (3:9), knowing Christ in resurrection power and
suffering fellowship (3:10), heavenly citizenship awaiting the Savior (3:20).
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "1": {
    "1": "<p>Paul as slave (doulos) of Christ Jesus — the letter opens with the most complete self-subordination Paul ever assumes. The crucified Christ is Lord; the apostle is his slave. This is not metaphor but theological identity: Paul's entire existence is defined by belonging to the one who bought him with his blood (1 Cor 6:20). The letter's Christology begins with ownership.</p>",
    "2": "<p>Grace and peace from God our Father and the Lord Jesus Christ — the risen Christ is co-source with the Father of the grace and peace the letter pronounces. As in every Pauline greeting, the Christological positioning is binitarian: Father and Son are a unified source of the divine gifts the congregation receives.</p>",
    "3": "<p>Every remembrance of the Philippians moves Paul to thanksgiving — the pastoral joy that pervades this letter flows from Christ who is its content. The congregation's partnership in the gospel is participation in the life of Christ; remembering them is in some sense remembering Christ's work among them.</p>",
    "4": "<p>Paul's prayer with joy — the joy (chara) that runs through this letter like a thread is specifically joy in the Lord Jesus (3:1; 4:4). The imprisonment does not diminish it because Christ, the source of joy, is not diminished by chains. Joy is the appropriate response to union with the risen Lord.</p>",
    "5": "<p>The Philippians' koinōnia (partnership/participation) in the gospel — their financial partnership in Paul's mission is participation in Christ's mission. The gospel is not Paul's but Christ's; to partner in its proclamation is to share in Christ's own work of reconciling the world.</p>",
    "6": "<p>He who began a good work in you will bring it to completion at the day of Christ Jesus — God is the initiating subject; Christ's day is the telos. The work begun at the Philippians' conversion (Acts 16:14-34: Lydia's opening heart, the jailer's believing household) is Christ's own work in them, guaranteed to completion by the faithfulness of God who raised Christ from the dead.</p>",
    "7": "<p>The Philippians are fellow partakers (synkoinōnous) with Paul in grace — in the defense and confirmation of the gospel. The grace they share is the grace of the Lord Jesus Christ whose apostle Paul is. Every participation in the apostolic mission is a participation in the christological grace that drives it.</p>",
    "8": "<p>Paul yearns for them with the splanchnois (affection/compassion) of Christ Jesus — not his own natural affection but Christ's own compassion flowing through him. The apostle has become so united with Christ that Christ's yearning for his people is expressed through Paul's yearning for the congregation. This is the pastoral implication of being in Christ.</p>",
    "9": "<p>The prayer for abounding love with epignōsis (full knowledge) — the love Paul prays for is modeled on Christ's love, which abounds in self-giving rather than self-seeking. The knowledge (epignōsis) is ultimately the knowledge of Christ (3:8: the surpassing worth of knowing Christ Jesus my Lord) that reorders all values.</p>",
    "10": "<p>Approving what is excellent (ta diapheronta) and being pure for the day of Christ — Christ's coming is the moral standard by which the present life is calibrated. Being blameless (aproskopoi) for that day means living now in a manner consistent with what the final judgment of the risen Christ will reveal.</p>",
    "11": "<p>Filled with the fruit of righteousness that comes through Jesus Christ — the fruit of righteousness is christologically generated, not self-produced. As the vine produces fruit only through the branches' union with the vine (John 15:4-5: apart from me you can do nothing), so the Philippians' righteous fruit flows through their union with Christ. The glory and praise belong to God precisely because the fruit is his gift.</p>",
    "12": "<p>What has happened to Paul has served the advance (prokopēn) of the gospel — the paradox of cruciform mission: the apostle's suffering, modeled on Christ's own, becomes the instrument of gospel advance. As Christ's crucifixion appeared to be defeat but was the event of salvation, Paul's imprisonment appears to be setback but is in fact missionary advance.</p>",
    "13": "<p>The imprisonment 'for Christ' (en Christō) has become known throughout the Praetorium — Paul's chains have a christological definition. He is not imprisoned as a criminal but as a witness to Christ; the Roman soldiers who guard him know this. The identification of imprisonment with Christ's cause makes the chains themselves a form of testimony to the crucified and risen Lord.</p>",
    "14": "<p>Brothers emboldened by Paul's chains to speak the word fearlessly — the paradoxical power of apostolic suffering. As Christ's death emboldened the disciples after the resurrection (Acts 4:13: they saw their boldness and recognized they had been with Jesus), so Paul's willingness to suffer for Christ emboldens the wider community to proclaim Christ without fear.</p>",
    "15": "<p>Christ proclaimed from envy and rivalry as well as from goodwill — the gospel's power is not diminished by the impurity of its human vehicles. The risen Christ is proclaimed; that proclamation has its own power regardless of the preacher's motives. This is the theological basis for Paul's equanimity: Christ is greater than the messenger's mixed motives.</p>",
    "16": "<p>Some preach from love, knowing Paul is set for the defense of the gospel — the apostolic mission as the defense (apologia) of the gospel before the world. Christ's own life was a defense of the Father's character; the apostle's imprisonment continues that apologetic mission. Those who understand this preach from love for Christ and for Paul's christological calling.</p>",
    "17": "<p>Others preach Christ from selfish ambition — even selfish preaching of Christ is contained within the greater purposes of the risen Lord. The cross's power is not neutralized by human sin in the preacher; the risen Christ is proclaimed, and the proclamation carries his power regardless of the preacher's private ambitions.</p>",
    "18": "<p>In every way Christ is proclaimed, and in that Paul rejoices — the Christological center of apostolic joy: Christ proclaimed is Christ present. Whether Paul is released or executed, whether preachers are sincere or ambitious, whether the message reaches one or thousands — Christ proclaimed is the indestructible content that transcends every circumstance.</p>",
    "19": "<p>This will turn out for Paul's sōtērian through the Spirit of Jesus Christ — the Spirit is specifically the Spirit of Jesus Christ, the risen Lord's own presence and power at work in the imprisoned apostle. The Spirit of Jesus Christ (Rom 8:9-11) is the guarantee of both present sustenance and final deliverance — the same Spirit who raised Christ from the dead.</p>",
    "20": "<p>Christ will be honored (megalynthēsetai) in Paul's body, whether through life or death — the body as the field of christological display. As Christ's own body was the location of both cruciform suffering and resurrection power, so the apostle's body participates in that same display. Whether Paul lives or dies, Christ is magnified — because death is Christ's and life is Christ's (v.21).</p>",
    "21": "<p>To live is Christ and to die is gain — the definitive christological summary of Paul's existence. Life = Christ: Christ is not added to life but is life itself for the apostle. Death = gain: not because life is bad but because death means more of Christ — fuller presence with the one who has become everything. The equation holds in either direction because Christ is both the content of life and the destination of death.</p>",
    "22": "<p>Continued life in the flesh means fruitful labor — the labor is fruitful because it participates in Christ's own ongoing mission. The risen Christ works through the apostle; the fruit produced is Christ's fruit through the apostle's ministry. Paul's preference for death is genuine but subordinated to Christ's purposes through the congregation's need.</p>",
    "23": "<p>The desire to depart and be with Christ is far better — syn Christō einai (to be with Christ) is the eschatological content of death's gain. Not mere survival after death, not soul-sleep, not dissolution — but personal presence with the risen Lord. The desire mirrors the risen Christ's own prayer: Father, I want those you have given me to be with me where I am (John 17:24).</p>",
    "24": "<p>To remain in the flesh is more necessary for their sake — the cruciform logic: what serves others takes precedence over personal preference. As Christ's death was pro nobis (for us), so the apostle's continued life is for the congregation. Self-giving love structures both the apostle's death-preference and his life-choice.</p>",
    "25": "<p>Paul's continued presence will advance their progress (prokopē) and joy in the faith — the apostolic mission as service to the congregation's growth in Christ. The joy of faith is participation in the joy of the risen Lord who rejoices over those who are his (Zeph 3:17; Luke 15:7). The apostle's ministry amplifies Christ's own joy over his people.</p>",
    "26": "<p>Boasting in Christ Jesus because of Paul's coming (parousia) — the apostle's arrival is a mini-parousia that generates boasting in Christ rather than in the apostle. Every genuine apostolic ministry points beyond itself to Christ; Paul's coming will increase their boasting in Christ, not in Paul. The eschatological frame of the true parousia relativizes every human presence.</p>",
    "27": "<p>Live as citizens (politeuesthe) worthy of the gospel of Christ — the gospel defines the polity and its obligations. As Roman colonists had obligations to Rome embodied in their colony's life, so the Philippians' obligations are to the gospel of Christ embodied in the church. The citizenship call is fundamentally christological: the gospel of Christ is the constitution of the new community.</p>",
    "28": "<p>Not frightened by opponents — the congregation's steadfastness is a sign of their salvation and of opponents' destruction. The crucified and risen Christ is the ground of their courage: if God is for us, who can be against us? (Rom 8:31). The same Christ who defeated death cannot be defeated by social pressure or religious opposition.</p>",
    "29": "<p>It has been granted (echaristhē — given as grace-gift) to suffer for Christ — a remarkable christological claim: suffering for Christ is a charisma alongside faith in him. The cross is not only the pattern of Christ's death but the pattern into which believers are drawn. Being granted to suffer for Christ is participation in the paschal mystery — a gift of divine grace, not punishment.</p>",
    "30": "<p>Engaged in the same conflict (agōna) that you saw in Paul — the christological conflict is one: the same Lord whose apostle was imprisoned in Philippi (Acts 16) is now being defended in Rome. Every believer's conflict for Christ is a participation in the one apostolic-christological mission that flows from the one crucified and risen Lord.</p>",
  },
  "2": {
    "1": "<p>If there is any encouragement in Christ, any comfort from love — the four conditionals assume all four are real and present. The encouragement is specifically in Christ (en Christō); all Christian consolation is christologically grounded. The comfort from love is the love of God revealed in Christ (Rom 8:39: nothing can separate us from the love of God in Christ Jesus our Lord).</p>",
    "2": "<p>Be of the same mind (to auto phronēte) — the single mind Paul calls for is the mind of Christ (v.5: phronēte en hymin ho kai en Christō Iēsou). The unity of the congregation is grounded in their common union with Christ; those who share one Lord share one mind. Division is the contradiction of the christological unity that already exists.</p>",
    "3": "<p>In humility (tapeinophrosynē) count others more significant than yourselves — the virtue Paul installs as Christian alternative to Greco-Roman honor-competition is the Christ-virtue par excellence. Christ himself took the form of a slave and humbled himself (vv.7-8); this tapeinophrosynē is not a Greek virtue but a christological one, derived from the descent of the Son of God.</p>",
    "4": "<p>Look not to your own interests but to the interests of others — the ethical principle is grounded in the Christ-pattern. The one who did not grasp at his own divine prerogatives (v.6) but emptied himself for others provides the template. The community that embodies this is enacting the Christ-hymn in its daily life together.</p>",
    "5": "<p>Have this mind among yourselves, which is yours in Christ Jesus — the transition to the Christ-hymn (vv.6-11) makes explicit that the ethical call is christologically based. The mind (phronēma) Paul calls for is already present in the community through Christ; it is not imposed from outside but drawn out from their union with the one who possessed and enacted it perfectly.</p>",
    "6": "<p>Who, being in the form of God, did not count equality with God a thing to be grasped — the pre-existent Son of God, existing in the mode of God's own reality (morphē theou), chose not to use his divine position for his own advantage. This is the foundational christological claim: the one who became human already possessed divine status and voluntarily set aside its exercise in self-giving love. The whole gospel hangs on this: it was God himself who came.</p>",
    "7": "<p>But emptied himself, taking the form of a servant (morphēn doulou labōn), being born in the likeness of men — the kenotic descent of the Son. Morphē doulou is the exact antithesis of morphē theou: from the mode of God's reality to the mode of a slave. The incarnation is not merely humility of attitude but ontological self-giving — God the Son takes on the slave-condition of humanity under sin's bondage. Born in the likeness of men: the true humanity of the Son is affirmed.</p>",
    "9": "<p>Therefore (dio kai) God has highly exalted him — the exaltation is the Father's answer to the Son's obedient self-humiliation. The resurrection and ascension are the divine vindication of the crucified slave: the name above every name (YHWH/Kyrios) is given to Jesus, confirming that his cruciform path was the path of true divine glory. The exaltation does not cancel the humiliation; the risen Christ remains the crucified one.</p>",
    "10": "<p>At the name of Jesus every knee should bow — the universal obeisance applying Isaiah 45:23 to Jesus. The citation of the YHWH-homage text to Jesus is the letter's most explicit identification of Jesus with the God of Israel. Every knee — heavenly, earthly, and under the earth — bows to the one who was crucified and raised. The scope is cosmic; the ground is the cross and resurrection.</p>",
    "12": "<p>Work out your own salvation with fear and trembling — the salvation to be worked out is the salvation Christ purchased. The fear and trembling (Exod 15:16; Ps 2:11) is appropriate before the God who enacted salvation through the cross and resurrection — a God not to be treated casually. The imperative rests on the indicative of v.13: God is the one at work; the congregation works out what God is working in.</p>",
    "13": "<p>It is God who works in you, both to will and to work for his good pleasure — the risen Christ works in the congregation through his Spirit (Rom 8:9-11). Even the desire to obey is the Spirit's gift. The God who raised Jesus from the dead (v.9's exaltation) is the same God who now works within the body of Christ to will and to do.</p>",
    "14": "<p>Do all things without grumbling (gongysmōn) — the wilderness generation's murmuring against Moses echoes as the negative example (1 Cor 10:10). The community of the risen Christ is the new Israel, called to a different pattern. Christ himself who endured the cross without complaint (Isa 53:7: he opened not his mouth) is the pattern against which murmuring is measured.</p>",
    "15": "<p>That you may be blameless (amōma) children of God shining as lights in the world — amōmos (without blemish — the sacrificial standard of Lev 1:3, 10) applied to the congregation. The blameless sacrifice is Christ himself (1 Pet 1:19: the lamb without blemish); the congregation participates in his blamelessness through union with him. Shining as lights (phōstēres) echoes Dan 12:3 and Christ's own identification of his disciples as the light of the world (Matt 5:14).</p>",
    "16": "<p>Holding fast the word of life — the word of life is the gospel of the crucified and risen Christ. The congregation that holds this word participates in Christ's life-giving power. At the day of Christ, the apostle's work will be vindicated not by his own eloquence but by the congregation's continued grip on the Christ-word.</p>",
    "17": "<p>If Paul is poured out as a libation upon the sacrifice of their faith — the apostle's potential martyrdom is theologically reframed as a sacrificial act poured over the congregation's faith as the primary offering. Christ's own death was the supreme sacrifice (Eph 5:2: a fragrant offering and sacrifice to God); apostolic martyrdom participates in that same sacrificial structure, completing what the cross accomplished in apostolic self-giving.</p>",
    "18": "<p>Rejoice and rejoice with me — the mutual christological joy: even martyrdom generates joy because the sacrificial death is a participation in Christ's own sacrificial death and the joy that lay beyond it (Heb 12:2: who for the joy set before him endured the cross). Christ's cross-to-resurrection joy is the template for apostolic joy through suffering.</p>",
    "19": "<p>I hope in the Lord Jesus to send Timothy — even Paul's travel plans are held in the Lord Jesus (en kyriō Iēsou). The resurrection-grounded hope relativizes all human uncertainty: Paul's plans are not his own but the Lord's, whose purposes are not frustrated by imprisonment. Timothy as emissary extends the apostolic — and ultimately christological — care for the congregation.</p>",
    "20": "<p>Timothy genuinely concerned (gnēsiōs merimnēsei) for the Philippians' welfare — the genuine care Timothy shows is Christomorphic: it mirrors the mind of Christ (v.5: phronein, mindset), oriented toward others rather than self. The contrast with those seeking their own interests (v.21) maps the christological alternative onto two patterns of human conduct.</p>",
    "21": "<p>For they all seek their own interests, not those of Jesus Christ — the inverse of the Christ-hymn: the pre-existent Son did not seek his own interests (v.4, 6) but gave himself for others. Those who seek their own interests are living by the old-age pattern the cross has overcome. Jesus Christ's interests define the pattern against which all service is measured.</p>",
    "22": "<p>Timothy has proved himself (dokimē) — as a son with a father — in the gospel. The father-son relationship echoes the divine Father-Son relationship that is the ground of all apostolic authority. Timothy learned gospel ministry by serving alongside Paul as Paul serves alongside Christ; the chain of christological imitation runs father-Son → apostle-co-worker → congregation.</p>",
    "23": "<p>Paul hopes to send Timothy as soon as he sees how it goes with him — apostolic planning under the sovereignty of the risen Christ. The uncertainty of Paul's legal outcome is held within the certainty that Christ's purposes will stand. The apostle's plans are submitted to the Lord who holds the outcome.</p>",
    "24": "<p>Paul trusts in the Lord that he will come soon — pepoitha en kyriō (I trust in the Lord). The confidence is christologically grounded: the same Lord who raised Christ from the dead is able to release the imprisoned apostle. Personal hope is held within the Lord's sovereign purposes.</p>",
    "25": "<p>Epaphroditus — brother, co-worker, fellow soldier, the Philippians' apostolos and leitourgos — the five-fold description culminates in two christological terms: apostolos (sent one — as Christ was sent by the Father, John 20:21: as the Father has sent me, I send you) and leitourgos (priestly minister — cultic service elevated to worship). Service to Paul in his imprisonment is service to Christ's purposes.</p>",
    "26": "<p>Epaphroditus distressed that the Philippians heard he was ill — the same Greek word (adēmonōn) used of Jesus in Gethsemane (Mark 14:33). Epaphroditus's pastoral anguish at the congregation's worry about him mirrors Christ's own anguish in the garden — the Christomorphic suffering of those who carry others' concerns as their own.</p>",
    "27": "<p>God had mercy on him — divine mercy (eleēsen) as the practical ground of pastoral survival. God did not allow Epaphroditus to die; this mercy is the Father's care for those who serve Christ faithfully. The mercy that saved Epaphroditus is the same mercy that raised Christ — active, resurrecting, life-giving mercy.</p>",
    "28": "<p>The congregation's rejoicing at Epaphroditus's return — the joy of the body of Christ reunited. The letter's pervasive joy (chairete, synchairete) has its ground in the risen Christ who has promised that his joy will be in his disciples and their joy complete (John 15:11). Each reunion of the body of Christ is a small anticipation of the ultimate reunion at the parousia.</p>",
    "29": "<p>Receive him in the Lord (en kyriō) with all joy — the christological welcome: receiving Epaphroditus in the Lord means recognizing his service as service to Christ, his return as a gift from the Lord, and his honor as reflecting Christ's own honor for the cruciform servant. Those who receive Christ's servants receive Christ (Matt 10:40).</p>",
    "30": "<p>He nearly died for the work of Christ, risking his life — the work of Christ is the content that makes Epaphroditus's risk meaningful. As Christ risked and lost his life in the work of salvation, those who serve the gospel participate in that same sacrificial logic. The risk of life for Christ's work is not foolishness but participation in the cross-pattern.</p>",
  },
  "3": {
    "1": "<p>Rejoice in the Lord — the christological specificity of joy: not general happiness or Stoic contentment but joy grounded in union with the risen Lord. The recurring rejoice (chairete) is not a command to feel happy but an invitation to draw from the inexhaustible joy that is in Christ regardless of circumstances.</p>",
    "2": "<p>Beware the dogs, the evil workers, the mutilators — the three-fold warning against those who require circumcision for salvation is a defense of the christological sufficiency of the cross. To add circumcision as a requirement is to claim that Christ's cross was insufficient. The mutilation charge (katatomē) strips the rite of its theological significance when detached from its christological fulfillment.</p>",
    "3": "<p>We are the circumcision — those who worship by the Spirit of God and glory in Christ Jesus and put no confidence in the flesh. The true circumcision is defined entirely christologically: worship in the Spirit poured out by the risen Christ (Acts 2:33), boasting in Christ Jesus rather than ethnic or legal credentials, and zero confidence in fleshly standing. The covenant community is now defined by relation to Christ rather than physical descent or ritual.</p>",
    "4": "<p>If anyone has reason for confidence in the flesh, I have more — Paul's rhetorical strategy: he out-ranks the Judaizing opponents on their own terms before discarding those terms. The point will be that the highest human credentials, when weighed against Christ, are worthless. This is not anti-Judaism but a christological supervaluation that relativizes everything else.</p>",
    "5": "<p>Paul's Jewish pedigree — circumcised eighth day, Israelite, Benjaminite, Hebrew of Hebrews, Pharisee — represents the highest religious standing in his world. All of it becomes loss in the Christ-calculation (v.7). The christological claim: knowing Christ surpasses even the most prestigious religious heritage. This is the measure of Christ's worth, not the dismissal of Judaism.</p>",
    "6": "<p>As to zeal, persecuting the church — Paul's pre-conversion persecution of the church, which he interpreted as Torah-faithfulness, was actually opposition to Christ himself (Acts 9:4-5: Saul, Saul, why are you persecuting me? — I am Jesus whom you are persecuting). The zeal for the law that drove the persecution was not wrong in itself but was misdirected against the one the law pointed toward.</p>",
    "7": "<p>Whatever gain I had, I counted as loss for Christ — the great christological revaluation. Encountering the risen Christ (Acts 9:3-6) did not add Christ to Paul's existing religious capital; it forced a complete reappraisal in which all previous gains were reclassified as losses. The risen Christ is incommensurably greater than any religious achievement.</p>",
    "8": "<p>I count everything as loss because of the surpassing worth of knowing Christ Jesus my Lord — the present tense: the revaluation is ongoing, not a past decision. Paul continues to assess everything in light of Christ and continues to find that knowing Christ (gnōsis Christou — relational, experiential knowledge) surpasses all. The skybala (dung/rubbish) is the strongest available Greek term for the worthlessness of everything else by comparison.</p>",
    "9": "<p>Be found in him, not having my own righteousness from the law but the righteousness from God through faith in Christ — the christological ground of justification. The righteousness (dikaiosynē ek theou) is externally given, mediated through Christ, received by faith. The contrast is total: law-generated self-righteousness vs. Christ-given God-righteousness. To be found in him at the day of judgment is to be covered by Christ's righteousness, not one's own.</p>",
    "11": "<p>That by any means possible I may attain the resurrection from the dead — the exanastasis (out-resurrection, the resurrection from among the dead ones) is Christ's own resurrection replicated in those who are his. Paul does not presume but presses. The resurrection he aims for is the participation in Christ's own resurrection body — the final christological transformation of 3:21.</p>",
    "12": "<p>Christ Jesus has made me his own (katelēmphthēn hypo Christou) — the Damascus road as the foundational christological seizure. Christ laid hold of Paul first; Paul now pursues Christ because he has already been apprehended by him. The grace of the initiative belongs entirely to Christ; the response of pressing forward belongs to Paul within that christological capture.</p>",
    "13": "<p>Forgetting what lies behind and straining forward to what lies ahead — the forward orientation is christological: what lies ahead is Christ himself in the fullness of the resurrection and the transformation of v.21. Forgetting the past means neither clinging to past failures (as if they can undo Christ's claim) nor resting on past achievements (as if they have already secured the prize).</p>",
    "14": "<p>I press on toward the goal for the prize of the upward call of God in Christ Jesus — the prize (brabeion) is the eschatological life with Christ, the full knowing of v.10. The upward call (anō klēsis) draws Paul toward Christ just as Christ draws all people to himself (John 12:32: I, when I am lifted up, will draw all people to myself). The resurrection is the upward pull on the apostle's entire existence.</p>",
    "15": "<p>Let those who are mature (teleioi) think this way — the irony: the mature are those who know they are not yet mature (v.12). True christological maturity is knowing that Christ has not yet been fully apprehended and pressing forward. The false mature are those who think they have arrived; true maturity is the forward-leaning posture of the one captured by Christ.</p>",
    "16": "<p>Hold true to what we have attained — the christological walk (stoichein) already begun must not be abandoned. The progress already made in knowing Christ and being transformed into his likeness is real and must be maintained. Regression in the christological life is the constant danger; perseverance in what has been received is the command.</p>",
    "17": "<p>Join in imitating me and keep your eyes on those who walk according to the example you have in us — apostolic imitation as christological formation. Paul can say 'imitate me' because he imitates Christ (1 Cor 11:1: be imitators of me as I am of Christ). The chain of imitation is christological: Christ's own pattern (the Christ-hymn) is reproduced in the apostle and is to be reproduced in the congregation.</p>",
    "18": "<p>Many walk as enemies of the cross of Christ — not merely theological opponents but those whose manner of life contradicts the cross-pattern. The cross defines a particular shape of existence: self-giving, other-oriented, glory-surrendering. Those who live for appetite, earthly honor, and their own things are structurally opposed to the cross even if they confess it verbally.</p>",
    "19": "<p>Their god is their belly, they glory in their shame, their minds are on earthly things — the threefold description is the inversion of the Christ-hymn: instead of not grasping (v.6), they grasp all earthly things; instead of self-emptying (v.7), they are full of their own desires; instead of the cross (v.8), they glory in shame. The enemies of the cross live by the anti-pattern of the Christ-hymn.</p>",
    "21": "<p>He will transform our lowly body to be like his glorious body, by the power that enables him to subject all things to himself — the eschatological christological transformation. Christ's resurrection body (sōma doxēs) is the template; his universal power is the instrument; the believer's transformed body is the result. The same power that raised Christ from the dead and exalted him over all things (the Christ-hymn's climax) will transform the body of humiliation into resurrection glory. This is the final word of the letter's Christology: the Christ who descended to slave-death will bring his people into his own risen glory.</p>",
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-christ', 'philippians')
    merge_comm(existing, NEW)
    save_comm('mkt-christ', 'philippians', existing)
    for ch in ['1', '2', '3']:
        print(f'  ch {ch}: {len(existing.get(ch, {}))} verses')
